using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ───────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_StartsWithAreaCodeInParentheses()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_MatchesFullPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_FullFormat_IsCorrect()
    {
        var result = _formatter.FormatPhoneNumber("8005559876");

        Assert.AreEqual("(800) 555-9876", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_WrongLength_Throws(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ───────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson");

        StringAssert.Contains(result, "Johnson");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_UsesMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Mr.");
        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_IsIncluded()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        Assert.AreEqual("Dear Dr. Jones,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitleProducesLowercaseDashedString()
    {
        var result = _formatter.GenerateSlug("Hello World");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartOrEndWithDash()
    {
        var result = _formatter.GenerateSlug("  --Hello World--  ");

        StringAssert.DoesNotMatch(result, new Regex(@"^-|-$"));
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharactersReplacedWithDashes()
    {
        var result = _formatter.GenerateSlug("C# is great & fun!");

        StringAssert.DoesNotMatch(result, new Regex(@"[^a-z0-9-]"));
        Assert.AreEqual("c-is-great-fun", result);
    }

    [TestMethod]
    public void GenerateSlug_ConsecutiveSpecialCharsCollapsedToSingleDash()
    {
        var result = _formatter.GenerateSlug("one   two---three");

        StringAssert.DoesNotMatch(result, new Regex("--"));
        Assert.AreEqual("one-two-three", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.5m);

        StringAssert.Matches(result, new Regex(@"^\$\d+\.\d{2}$"));
        Assert.AreEqual("$1234.50", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
        Assert.AreEqual("€19.99", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(-5.5m);

        StringAssert.StartsWith(result, "$-");
        StringAssert.EndsWith(result, ".50");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ShowsZeroWithDecimals()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}
